#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    const __global float *power,
    const __global float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int block_id_x = get_group_id(0);
    int block_id_y = get_group_id(1);

    int c_start = block_id_x * BLOCK_SIZE;
    int r_start = block_id_y * BLOCK_SIZE;

    int c_end = c_start + BLOCK_SIZE;
    if (c_end > col) c_end = col;

    int r_end = r_start + BLOCK_SIZE;
    if (r_end > row) r_end = row;

    int local_c = get_local_id(0);
    int local_r = get_local_id(1);

    int c = c_start + local_c;
    int r = r_start + local_r;

    if (r >= r_end || c >= c_end) {
        return;
    }

    int idx = r * col + c;
    float current_temp = temp[idx];

    for (int iter = 0; iter < num_iterations; iter++) {
        float delta;

        bool r0 = (r == 0);
        bool r_max = (r == row - 1);
        bool c0 = (c == 0);
        bool c_max = (c == col - 1);

        float t_up = (r0) ? current_temp : temp[idx - col];
        float t_down = (r_max) ? current_temp : temp[idx + col];
        float t_left = (c0) ? current_temp : temp[idx - 1];
        float t_right = (c_max) ? current_temp : temp[idx + 1];

        if (r0 && c0) {
            delta = Cap_1 * (power[idx] +
                (t_right - current_temp) * Rx_1 +
                (t_down - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r0 && c_max) {
            delta = Cap_1 * (power[idx] +
                (t_left - current_temp) * Rx_1 +
                (t_down - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r_max && c_max) {
            delta = Cap_1 * (power[idx] +
                (t_left - current_temp) * Rx_1 +
                (t_up - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r_max && c0) {
            delta = Cap_1 * (power[idx] +
                (t_right - current_temp) * Rx_1 +
                (t_up - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r0) {
            delta = Cap_1 * (power[idx] +
                (t_right + t_left - 2.0f * current_temp) * Rx_1 +
                (t_down - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (c_max) {
            delta = Cap_1 * (power[idx] +
                (t_down + t_up - 2.0f * current_temp) * Ry_1 +
                (t_left - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r_max) {
            delta = Cap_1 * (power[idx] +
                (t_right + t_left - 2.0f * current_temp) * Rx_1 +
                (t_up - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (c0) {
            delta = Cap_1 * (power[idx] +
                (t_down + t_up - 2.0f * current_temp) * Ry_1 +
                (t_right - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        } else {
            delta = Cap_1 * (power[idx] +
                (t_down + t_up - 2.0f * current_temp) * Ry_1 +
                (t_right + t_left - 2.0f * current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }

        current_temp = current_temp + delta;

        if (iter < num_iterations - 1) {
            temp[idx] = current_temp;
        }
    }

    result[idx] = current_temp;
}
